mapper.select:
SELECT id, parent_id, category_name, description, display_order, is_active, created_at, updated_at
FROM categories
WHERE id = #{id}

WITH RECURSIVE category_tree AS ( -- 루트 카테고리 SELECT id, parent_id, category_name, description, display_order, is_active, created_at, updated_at, 1 AS level FROM categories WHERE id = #{rootId}
UNION ALL
-- 자식 카테고리 SELECT c.id, c.parent_id, c.category_name, c.description, c.display_order, c.is_active, c.created_at, c.updated_at, ct.level + 1 FROM categories c INNER JOIN category_tree ct ON c.parent_id = ct.id WHERE c.is_active = true ) SELECT id, parent_id, category_name, description, display_order, is_active, created_at, updated_at FROM category_tree ORDER BY level, display_order

WITH RECURSIVE descendants AS ( -- 시작 카테고리 SELECT id, parent_id, category_name, description, display_order, is_active, created_at, updated_at FROM categories WHERE parent_id = #{parentId}
UNION ALL
-- 재귀적으로 자식 조회 SELECT c.id, c.parent_id, c.category_name, c.description, c.display_order, c.is_active, c.created_at, c.updated_at FROM categories c INNER JOIN descendants d ON c.parent_id = d.id ) SELECT id, parent_id, category_name, description, display_order, is_active, created_at, updated_at FROM descendants ORDER BY display_order
